# cf common crawl ???# On a 20 offre par page, donc on devrait scrape 40 item.# Objectif : une ligne = 1 offre avec, infos/détails offre, ID, infos entreprise.import scrapyclass HelloWork2Spider(scrapy.Spider):    name = "hello_work2"    allowed_domains = ["www.hellowork.com"]    # On remarque que qu'il n'y a pas de lien pour la page suivante    # Or en regardant l'url on remarque que ?p=2 amène sur la deuxième page.    # Donc on va construire nous même l'url à suivre.    start_urls = [        "https://www.hellowork.com/fr-fr/emploi/ville_toulouse-31000.html"    ]    def __init__(self):        self.current_page = 1    def process_next_page(self) -> str:        # Condition d'arrêt        if self.current_page >= 2 or self.current_page >= 974:            return None        self.current_page += 1        return f"{self.start_urls[0]}?p={self.current_page}"    def parse(self, response):        offres = response.xpath('//a[@data-cy="offerTitle"]')        for offre in offres:            item = {                "nom_offre": offre.xpath(                    './/p[contains(@class,"tw-typo-l")]/text()'                ).get(),                "nom_entreprise": offre.xpath(                    './/p[contains(@class,"tw-typo-s")]/text()'                ).get(),                "url_offre": response.urljoin(offre.xpath("./@href").get()),            }            yield response.follow(                item["url_offre"],                callback=self.parse_details,                meta={"item": item},            )        next_page = self.process_next_page()        if next_page:            yield response.follow(next_page, callback=self.parse)    def parse_details(self, response):        # .meta["item"] correspond au dictionnaire item, auquel        # on va ajouter des éléments de la deuxième page.        item = response.meta["item"]        tags = response.xpath(            '//ul[contains(@class,"tw-flex tw-flex-wrap tw-gap-3")]//li//text()'        ).getall()        description_poste = " ".join(            response.xpath(                '//div[contains(@class, "tw-leading-relaxed")]/p/text()'            ).getall()        )        profile_recherche = " ".join(            response.xpath(                '//p[contains(@class, "tw-typo-long-m tw-break-words")]/text()'            ).getall()        )        clean_tags = [" ".join(tag.split()) for tag in tags if tag.strip()]        item["tags"] = clean_tags        item["description_poste"] = description_poste        item["profile_recherche"] = profile_recherche        yield item